svg.script:
(function() {
  var STORAGE_KEY = 'saas-platform-positions';
  var svg = document.documentElement;
  var dragging = null;
  var offset = { x: 0, y: 0 };
  var origTranslate = { x: 0, y: 0 };

  function getSVGPoint(evt) {
    var pt = svg.createSVGPoint();
    pt.x = evt.clientX;
    pt.y = evt.clientY;
    return pt.matrixTransform(svg.getScreenCTM().inverse());
  }

  function parseTranslate(el) {
    var t = el.getAttribute('transform');
    var m = t.match(/translate\(\s*([-\d.]+)\s*,\s*([-\d.]+)\s*\)/);
    return m ? { x: parseFloat(m[1]), y: parseFloat(m[2]) } : { x: 0, y: 0 };
  }

  function setTranslate(el, x, y) {
    el.setAttribute('transform', 'translate(' + x + ', ' + y + ')');
  }

  function savePositions() {
    var positions = {};
    var els = svg.querySelectorAll('[data-drag]');
    for (var i = 0; i < els.length; i++) {
      var el = els[i];
      var pos = parseTranslate(el);
      positions[el.getAttribute('data-drag')] = pos;
    }
    try { localStorage.setItem(STORAGE_KEY, JSON.stringify(positions)); } catch(e) {}
  }

  function loadPositions() {
    try {
      var data = localStorage.getItem(STORAGE_KEY);
      if (!data) return;
      var positions = JSON.parse(data);
      var els = svg.querySelectorAll('[data-drag]');
      for (var i = 0; i < els.length; i++) {
        var el = els[i];
        var id = el.getAttribute('data-drag');
        if (positions[id]) {
          setTranslate(el, positions[id].x, positions[id].y);
        }
      }
    } catch(e) {}
  }

  svg.addEventListener('mousedown', function(evt) {
    var target = evt.target;
    while (target && target !== svg) {
      if (target.hasAttribute && target.hasAttribute('data-drag')) {
        dragging = target;
        var pt = getSVGPoint(evt);
        origTranslate = parseTranslate(dragging);
        offset.x = pt.x - origTranslate.x;
        offset.y = pt.y - origTranslate.y;
        dragging.style.cursor = 'grabbing';
        evt.preventDefault();
        return;
      }
      target = target.parentNode;
    }
  });

  svg.addEventListener('mousemove', function(evt) {
    if (!dragging) return;
    evt.preventDefault();
    var pt = getSVGPoint(evt);
    setTranslate(dragging, pt.x - offset.x, pt.y - offset.y);
  });

  svg.addEventListener('mouseup', function() {
    if (dragging) {
      dragging.style.cursor = '';
      dragging = null;
      savePositions();
    }
  });

  svg.addEventListener('mouseleave', function() {
    if (dragging) {
      dragging.style.cursor = '';
      dragging = null;
      savePositions();
    }
  });

  // Touch support
  svg.addEventListener('touchstart', function(evt) {
    var touch = evt.touches[0];
    var target = document.elementFromPoint(touch.clientX, touch.clientY);
    while (target && target !== svg) {
      if (target.hasAttribute && target.hasAttribute('data-drag')) {
        dragging = target;
        var pt = getSVGPoint(touch);
        origTranslate = parseTranslate(dragging);
        offset.x = pt.x - origTranslate.x;
        offset.y = pt.y - origTranslate.y;
        evt.preventDefault();
        return;
      }
      target = target.parentNode;
    }
  }, { passive: false });

  svg.addEventListener('touchmove', function(evt) {
    if (!dragging) return;
    evt.preventDefault();
    var pt = getSVGPoint(evt.touches[0]);
    setTranslate(dragging, pt.x - offset.x, pt.y - offset.y);
  }, { passive: false });

  svg.addEventListener('touchend', function() {
    if (dragging) {
      dragging = null;
      savePositions();
    }
  });

  // Set cursor on draggable elements
  var els = svg.querySelectorAll('[data-drag]');
  for (var i = 0; i < els.length; i++) {
    els[i].style.cursor = 'grab';
  }

  // Load saved positions
  loadPositions();
})();
